def decode_cyclic(s: str) -> str:
    decoded_chars = []
    shift = 3  # Assuming a shift of 3, change if needed

    for char in s:
        if 'a' <= char <= 'z':
            # Shift back within lowercase letters
            new_char = chr((ord(char) - ord('a') - shift) % 26 + ord('a'))
        elif 'A' <= char <= 'Z':
            # Shift back within uppercase letters
            new_char = chr((ord(char) - ord('A') - shift) % 26 + ord('A'))
        else:
            # Leave non-alphabetic characters unchanged
            new_char = char

        decoded_chars.append(new_char)

    return ''.join(decoded_chars)

# Example usage
encoded_string = "Khoor Zruog"  # This is "Hello World" encoded with a shift of 3
decoded_string = decode_cyclic(encoded_string)
print(decoded_string)  # Output: "Hello World"

def sum_squares(lst):
    total = 0
    for i, num in enumerate(lst):
        if i % 3 == 0:
            total += num ** 2  # Square the number if index is a multiple of 3
        elif i % 4 == 0:
            total += num ** 3  # Cube the number if index is a multiple of 4 and not a multiple of 3
        else:
            total += num  # Keep the number unchanged if index is not a multiple of 3 or 4
    return total

# Test cases
print(sum_squares([1, 2, 3]))  # Output: 6
print(sum_squares([]))          # Output: 0
print(sum_squares([-1, -5, 2, -1, -5]))  # Output: -126

