def max_fill(grid, capacity):
    total_water = 0

    # Calculate total amount of water in the grid
    for row in grid:
        total_water += sum(row)

    # Calculate the number of times we need to lower the buckets
    # We divide total_water by capacity and round up to ensure we account for any remainder
    if capacity > 0:
        return math.ceil(total_water / capacity)
    else:
        return 0  # If capacity is 0 or less, we can't extract water

