def match_parens(lst):
    def balance(s):
        open_count = 0
        close_count = 0
        for char in s:
            if char == '(':
                open_count += 1
            elif char == ')':
                close_count += 1
            # If at any point close_count exceeds open_count, it's unbalanced
            if close_count > open_count:
                return False
        return open_count == close_count

    s1, s2 = lst[0], lst[1]

    # Check both concatenation orders
    return 'Yes' if (balance(s1 + s2) or balance(s2 + s1)) else 'No'

# Example usage
print(match_parens(['()(', ')']))  # Output: 'Yes'
print(match_parens([')', ')']))     # Output: 'No'

