def get_odd_collatz(n):
    # Initialize an empty set to store odd numbers
    odd_numbers = set()

    # Start the Collatz sequence
    current = n
    while current != 1:
        # If the current number is odd, add it to the set
        if current % 2 != 0:
            odd_numbers.add(current)
        # Apply the Collatz rules
        if current % 2 == 0:
            current //= 2  # If even, divide by 2
        else:
            current = 3 * current + 1  # If odd, apply 3n + 1

    # Don't forget to add 1 to the set since the sequence ends with 1
    odd_numbers.add(1)

    # Return the sorted list of odd numbers
    return sorted(odd_numbers)

# Example usage:
print(get_odd_collatz(5))  # Output: [1, 5]

def get_odd_collatz(n):
    if n <= 0:
        raise ValueError("Input must be a positive integer.")

    collatz_sequence = []

    while n != 1:
        collatz_sequence.append(n)
        if n % 2 == 0:
            n //= 2
        else:
            n = 3 * n + 1

    collatz_sequence.append(1)  # Append the last element, which is always 1

    # Extract odd numbers and return them sorted
    odd_numbers = sorted(num for num in collatz_sequence if num % 2 != 0)

    return odd_numbers

# Example usage
print(get_odd_collatz(5))  # Output: [1, 5]

def valid_date(date):
    # Check if the date string is empty
    if not date:
        return False

    # Check if the date format is correct (mm-dd-yyyy)
    if len(date) != 10 or date[2] != '-' or date[5] != '-':
        return False

    # Split the date into components
    try:
        month, day, year = map(int, date.split('-'))
    except ValueError:
        return False  # If conversion to int fails, return False

    # Check the month range
    if month < 1 or month > 12:
        return False

    # Check the day range based on the month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        if day < 1 or day > 30:
            return False
    elif month == 2:
        if day < 1 or day > 29:
            return False

    # If all checks pass, the date is valid
    return True

# Example usage:
print(valid_date('03-11-2000'))  # True
print(valid_date('15-01-2012'))  # False
print(valid_date('04-0-2040'))   # False
print(valid_date('06-04-2020'))  # True
print(valid_date('06/04/2020'))  # False

def valid_date(date):
    # Check if the date string is empty
    if not date:
        return False

    # Check if the date matches the required format mm-dd-yyyy
    if len(date) != 10 or date[2] != '-' or date[5] != '-':
        return False

    # Split the date into month, day, and year
    try:
        month, day, year = map(int, date.split('-'))
    except ValueError:
        return False  # Handle non-integer values

    # Validate month
    if month < 1 or month > 12:
        return False

    # Validate day based on the month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        if day < 1 or day > 30:
            return False
    elif month == 2:
        if day < 1 or day > 29:
            return False

    return True

# Example usage:
print(valid_date('03-11-2000'))  # True
