def split_words(txt):
    # Check if there are any whitespace characters in the text
    if ' ' in txt:
        return txt.split()

    # Check if there are any commas in the text
    elif ',' in txt:
        return txt.split(',')

    # If no whitespace or commas, count the number of lowercase letters
    else:
        # Count the lowercase letters with odd order in the alphabet
        odd_count = sum(1 for char in txt if char.islower() and (ord(char) - ord('a')) % 2 == 1)
        return odd_count

# Examples
print(split_words("Hello world!"))  # ➞ ["Hello", "world!"]
print(split_words("Hello,world!"))  # ➞ ["Hello", "world!"]
print(split_words("abcdef"))         # ➞ 3

