def is_prime(n):
    """Check if a number is prime."""
    if n <= 1:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def intersection(interval1, interval2):
    """Determine if the length of the intersection of two intervals is a prime number."""
    start1, end1 = interval1
    start2, end2 = interval2

    # Calculate the intersection
    start = max(start1, start2)
    end = min(end1, end2)

    # Check if there is an intersection
    if start > end:
        return "NO"

    # Calculate the length of the intersection
    length = end - start + 1  # +1 because intervals are closed

    # Check if the length is a prime number
    if is_prime(length):
        return "YES"
    else:
        return "NO"

# Sample tests
print(intersection((1, 2), (2, 3)))  # Output: "NO"
print(intersection((-1, 1), (0, 4)))  # Output: "NO"
print(intersection((-3, -1), (-5, 5)))  # Output: "YES"

def tri(n):
    # Initialize the list to hold the Tribonacci numbers
    tribonacci_sequence = []

    # Define the base case
    for i in range(n + 1):
        if i == 1:
            tribonacci_sequence.append(3)  # tri(1) = 3
        elif i == 0:
            tribonacci_sequence.append(1)  # tri(0) = 1
        elif i % 2 == 0:  # even n
            tribonacci_sequence.append(1 + i / 2)
        else:  # odd n
            # tri(n) = tri(n - 1) + tri(n - 2) + tri(n + 1)
            # We need to ensure we calculate this correctly
            if i + 1 <= n:
                tribonacci_sequence.append(
                    tribonacci_sequence[i - 1] + tribonacci_sequence[i - 2] + tribonacci_sequence[i + 1]
                )
            else:
                tribonacci_sequence.append(
                    tribonacci_sequence[i - 1] + tribonacci_sequence[i - 2] + 3  # for tri(1)
                )

    return tribonacci_sequence

# Example usage
print(tri(3))  # Output: [1, 3, 2, 8]

def tri(n):
    # Initialize a list to hold the Tribonacci numbers
    tribonacci = []

    # Function to calculate the tribonacci number at index n
    def tribonacci_number(n):
        if n == 1:
            return 3
        elif n == 2:
            return 2
        elif n % 2 == 0:
            return 1 + n / 2
        else:
            return tribonacci_number(n - 1) + tribonacci_number(n - 2) + tribonacci_number(n + 1)

    # Calculate the first n + 1 numbers
    for i in range(n + 1):
        tribonacci.append(tribonacci_number(i))

    return tribonacci

# Example usage
print(tri(3))  # Output: [1, 3, 2, 8]

