def tri(n):
    # Create a list to hold the first n + 1 numbers of the Tribonacci sequence
    tribonacci_sequence = []

    # Define the base case
    for i in range(n + 1):
        if i == 1:
            tribonacci_sequence.append(3)  # tri(1) = 3
        elif i == 0:
            tribonacci_sequence.append(1)  # tri(0) = 1
        elif i % 2 == 0:
            tribonacci_sequence.append(1 + i / 2)  # tri(n) = 1 + n / 2 for even n
        else:
            # tri(n) = tri(n - 1) + tri(n - 2) + tri(n + 1) for odd n
            if i - 1 < len(tribonacci_sequence):
                tri_n_minus_1 = tribonacci_sequence[i - 1]
            else:
                tri_n_minus_1 = 0

            if i - 2 < len(tribonacci_sequence):
                tri_n_minus_2 = tribonacci_sequence[i - 2]
            else:
                tri_n_minus_2 = 0

            if i + 1 < len(tribonacci_sequence):
                tri_n_plus_1 = tribonacci_sequence[i + 1]
            else:
                tri_n_plus_1 = 0

            tribonacci_sequence.append(tri_n_minus_1 + tri_n_minus_2 + tri_n_plus_1)

    return tribonacci_sequence

