def is_nested(string):
    open_count = 0
    nested = False

    for char in string:
        if char == '[':
            open_count += 1
        elif char == ']':
            if open_count > 0:
                open_count -= 1
                # We have a valid closing bracket, check if we were nested
                if open_count > 0:
                    nested = True

    return nested

