import math

def special_factorial(n):
    if n <= 0:
        return 1  # Return 1 for n <= 0 as a convention (0! is 1)

    result = 1
    for i in range(1, n + 1):
        result *= math.factorial(i)

    return result

# Example usage
print(special_factorial(4))  # Output: 288

def even_odd_count(num):
    # Convert the number to a string and remove the sign if it's negative
    num_str = str(abs(num))

    even_count = 0
    odd_count = 0

    for digit in num_str:
        if int(digit) % 2 == 0:
            even_count += 1
        else:
            odd_count += 1

    return (even_count, odd_count)

