def int_to_mini_roman(number):
    if not (1 <= number <= 1000):
        raise ValueError("Number must be between 1 and 1000 inclusive.")

    # Define the mapping of integers to Roman numerals
    roman_numerals = [
        (1000, 'm'), (900, 'cm'), (500, 'd'), (400, 'cd'),
        (100, 'c'), (90, 'xc'), (50, 'l'), (40, 'xl'),
        (10, 'x'), (9, 'ix'), (5, 'v'), (4, 'iv'),
        (1, 'i')
    ]

    result = []

    for value, numeral in roman_numerals:
        while number >= value:
            result.append(numeral)
            number -= value

    return ''.join(result)

# Examples
print(int_to_mini_roman(19))   # Output: 'xix'
print(int_to_mini_roman(152))  # Output: 'clii'
print(int_to_mini_roman(426))  # Output: 'cdxxvi'

def do_algebra(operators, operands):
    # Start with the first operand
    result = operands[0]

    # Iterate through each operator and the corresponding operand
    for i in range(len(operators)):
        if operators[i] == '+':
            result += operands[i + 1]
        elif operators[i] == '-':
            result -= operands[i + 1]
        elif operators[i] == '*':
            result *= operands[i + 1]
        elif operators[i] == '//':
            result //= operands[i + 1]
        elif operators[i] == '**':
            result **= operands[i + 1]

    return result

# Example usage:
