def decode_shift(s: str, shift: int = 1) -> str:
    decoded_chars = []

    for char in s:
        if char.isalpha():  # Check if character is a letter
            shift_amount = shift % 26  # Handle wrap-around using modulo
            if char.islower():
                # Decode lowercase letters
                new_char = chr((ord(char) - ord('a') - shift_amount) % 26 + ord('a'))
            elif char.isupper():
                # Decode uppercase letters
                new_char = chr((ord(char) - ord('A') - shift_amount) % 26 + ord('A'))
            decoded_chars.append(new_char)
        else:
            # Non-alphabetic characters are added unchanged
            decoded_chars.append(char)

    return ''.join(decoded_chars)

# Example usage:
encoded_string = "bcd"  # Assuming this was encoded with a shift of 1
decoded_string = decode_shift(encoded_string)
print(decoded_string)  # Output should be "abc"

