def largest_prime_factor(n: int) -> int:
    # Start with the smallest prime factor
    factor = 2
    # Keep dividing n by factor until it is no longer divisible
    while n > 1:
        if n % factor == 0:
            n //= factor  # Divide n by the factor
        else:
            factor += 1   # Move to the next possible factor
    return factor

# Example usage:
print(largest_prime_factor(13195))  # Output: 29
print(largest_prime_factor(2048))   # Output: 2

def largest_prime_factor(n: int) -> int:
    # Start with the smallest prime factor
    factor = 2

    # Divide n by factor until it is no longer divisible
    while n > 1:
        if n % factor == 0:
            n //= factor  # Divide n by the current factor
        else:
            factor += 1  # Move to the next potential factor

    return factor

# Example usage
