from typing import List

def parse_nested_parens(paren_string: str) -> List[int]:
    def max_depth(group: str) -> int:
        current_depth = 0
        max_depth = 0

        for char in group:
            if char == '(':
                current_depth += 1
                max_depth = max(max_depth, current_depth)
            elif char == ')':
                current_depth -= 1

        return max_depth

    groups = paren_string.split()
    return [max_depth(group) for group in groups]

# Example usage:
print(parse_nested_parens('(()()) ((())) () ((())()())'))  # Output: [2, 3, 1, 3]

def search(lst):
    # Create a dictionary to count the frequency of each number
    frequency = {}

    for num in lst:
        if num in frequency:
            frequency[num] += 1
        else:
            frequency[num] = 1

    # Initialize the result variable to store the greatest integer found
    result = -1

    # Iterate through the frequency dictionary
    for num, freq in frequency.items():
        # Check if the frequency is greater than or equal to the number itself
        if freq >= num:
            # Update result if this number is greater than the current result
            result = max(result, num)

    return result

# Test cases
print(search([4, 1, 2, 2, 3, 1]))  # Output: 2
print(search([1, 2, 2, 3, 3, 3, 4, 4, 4]))  # Output: 3
print(search([5, 5, 4, 4, 4]))  # Output: -1

def is_simple_power(x, n):
    if n <= 1:
        return False  # n must be greater than 1 for valid power calculations
    if x < 1:
        return False  # x must be a positive number

    power = 1
    while True:
        result = n ** power
        if result == x:
            return True
        elif result > x:
            return False
        power += 1

# Example usage:
print(is_simple_power(1, 4))  # => True
print(is_simple_power(2, 2))  # => True
print(is_simple_power(8, 2))  # => True
print(is_simple_power(3, 2))  # => False
print(is_simple_power(3, 1))  # => False
print(is_simple_power(5, 3))  # => False

from typing import List, Tuple

def sum_product(numbers: List[int]) -> Tuple[int, int]:
    if not numbers:
        return (0, 1)

    total_sum = sum(numbers)
    total_product = 1
    for number in numbers:
        total_product *= number

    return (total_sum, total_product)

# Example usage:
print(sum_product([]))           # Output: (0, 1)
print(sum_product([1, 2, 3, 4])) # Output: (10, 24)

