def sort_array(array):
    if not array:
        return []

    # Calculate the sum of the first and last element
    first_last_sum = array[0] + array[-1]

    # Sort the array based on the sum being odd or even
    if first_last_sum % 2 == 0:
        # Even sum: sort in descending order
        return sorted(array, reverse=True)
    else:
        # Odd sum: sort in ascending order
        return sorted(array)

# Example usage:
print(sort_array([]))  # Output: []
print(sort_array([5]))  # Output: [5]
print(sort_array([2, 4, 3, 0, 1, 5]))  # Output: [0, 1, 2, 3, 4, 5]
print(sort_array([2, 4, 3, 0, 1, 5, 6]))  # Output: [6, 5, 4, 3, 2, 1, 0]

from typing import List

def rolling_max(numbers: List[int]) -> List[int]:
    if not numbers:
        return []

    max_so_far = numbers[0]
    result = [max_so_far]

    for number in numbers[1:]:
        if number > max_so_far:
            max_so_far = number
        result.append(max_so_far)

    return result

# Example usage
