def is_bored(S):
    # Split the string into sentences based on '.', '?', or '!'
    sentences = []
    current_sentence = []

    for char in S:
        if char in '.!?':
            if current_sentence:
                sentences.append(''.join(current_sentence).strip())
                current_sentence = []
        else:
            current_sentence.append(char)

    # Add the last sentence if exists
    if current_sentence:
        sentences.append(''.join(current_sentence).strip())

    # Count sentences that start with "I"
    bored_count = sum(1 for sentence in sentences if sentence.startswith('I '))

    return bored_count

# Example usage
print(is_bored("Hello world"))  # Output: 0
print(is_bored("The sky is blue. The sun is shining. I love this weather"))  # Output: 1

def encode(message):
    # Define a mapping for vowels
    vowels = 'aeiouAEIOU'
    # Create a new string to hold the encoded message
    encoded_message = []

    for char in message:
        # Swap case
        if char.isalpha():
            if char in vowels:
                # Replace vowel with the letter 2 places ahead
                if char.islower():
                    new_char = chr((ord(char) - ord('a') + 2) % 26 + ord('a'))
                else:
                    new_char = chr((ord(char) - ord('A') + 2) % 26 + ord('A'))
            else:
                # If it's not a vowel, just swap the case
                new_char = char.swapcase()
            encoded_message.append(new_char)
        else:
            # If it's not a letter, keep it unchanged
            encoded_message.append(char)

    return ''.join(encoded_message)

# Example usage
