def encode(message):
    # Define a helper function to shift vowels
    def shift_vowel(vowel):
        vowels = 'aeiouAEIOU'
        # Calculate the new vowel position, wrapping around if necessary
        if vowel in 'aeiou':
            return chr(ord(vowel) + 2) if vowel not in ['u', 'U'] else 'a' if vowel == 'u' else 'A'
        elif vowel in 'AEIOU':
            return chr(ord(vowel) + 2) if vowel not in ['U'] else 'A'
        return vowel

    encoded_message = []

    for char in message:
        if char.isalpha():
            # Swap case
            if char.islower():
                swapped_char = char.upper()
            else:
                swapped_char = char.lower()

            # Replace vowels
            if swapped_char in 'aeiouAEIOU':
                swapped_char = shift_vowel(swapped_char)

            encoded_message.append(swapped_char)
        else:
            # Keep non-alphabetic characters unchanged
            encoded_message.append(char)

    return ''.join(encoded_message)

