def check_dict_case(d):
    if not d:  # Check if the dictionary is empty
        return False

    # Check the case of the first key
    first_key = next(iter(d))  # Get the first key from the dictionary
    is_lower = first_key.islower()

    for key in d.keys():
        if (is_lower and not key.islower()) or (not is_lower and not key.isupper()):
            return False

    return True

